#!/usr/bin/env bash
# ctrl-bundle.sh — auto-generated by bundle.sh, do not edit
set -euo pipefail

CTRL_SELF_DIR="$(cd "$(dirname "$(readlink -f "${BASH_SOURCE[0]}")")" && pwd)"
CTRL_VERSION="$(cat "${CTRL_SELF_DIR}/VERSION" 2>/dev/null || echo unknown)"

# ════════════════════════════════════════════════════════════════════════════
# lib/core.sh
# ════════════════════════════════════════════════════════════════════════════
# core.sh — config loading, logging, OS detection, utility helpers

CTRL_JOURNAL_DIR="${HOME}/.local/share/ctrl"
CTRL_JOURNAL="${CTRL_JOURNAL_DIR}/journal.jsonl"
CTRL_DRY_RUN="${CTRL_DRY_RUN:-0}"
CTRL_VERBOSE="${CTRL_VERBOSE:-0}"

# ── colour ────────────────────────────────────────────────────────────────────
if [[ -t 1 ]]; then
  BOLD=$'\033[1m'; DIM=$'\033[2m'
  RED=$'\033[31m'; GREEN=$'\033[32m'; YELLOW=$'\033[33m'; BLUE=$'\033[34m'
  RESET=$'\033[0m'
else
  BOLD=''; DIM=''; RED=''; GREEN=''; YELLOW=''; BLUE=''; RESET=''
fi

# ── logging ───────────────────────────────────────────────────────────────────
msg()       { echo "${BLUE}${BOLD}==>${RESET} $*"; }
msg_ok()    { echo "${GREEN}${BOLD}ok${RESET} $*"; }
msg_warn()  { echo "${YELLOW}${BOLD}warn${RESET} $*" >&2; }
msg_error() { echo "${RED}${BOLD}error${RESET} $*" >&2; }
msg_verbose() { [[ "${CTRL_VERBOSE}" == "1" ]] && echo "${DIM}[verbose]${RESET} $*" >&2 || true; }

fail() { msg_error "$*"; exit 1; }

require_cmd() {
  for cmd in "$@"; do
    command -v "$cmd" >/dev/null 2>&1 || fail "Required command not found: ${cmd}"
  done
}

has_cmd() { command -v "$1" >/dev/null 2>&1; }

# ── dry-run executor ──────────────────────────────────────────────────────────
# Usage: run_op "description" cmd arg1 arg2 ...
run_op() {
  local desc="$1"; shift
  if [[ "${CTRL_DRY_RUN}" == "1" ]]; then
    echo "${DIM}[DRY-RUN]${RESET} ${desc}: $*"
    return 0
  fi
  msg_verbose "exec: $*"
  "$@"
}

# ── config ────────────────────────────────────────────────────────────────────
CTRL_CONFIG_FILE="${CTRL_CONFIG:-}"
CTRL_META_PROJECT=""
CTRL_META_REGISTRY=""
CTRL_META_SSH_HOST=""
CTRL_META_SSH_USER="root"
CTRL_META_SSH_PORT="22"
CTRL_META_SSH_KEY=""
CTRL_META_COMPOSE_PATH="/opt/scaffold/docker-compose.yml"
CTRL_META_REMOTE_DIR="/opt/scaffold"

_find_config() {
  if [[ -n "${CTRL_CONFIG_FILE}" ]]; then
    [[ -f "${CTRL_CONFIG_FILE}" ]] || fail "Config file not found: ${CTRL_CONFIG_FILE}"
    return
  fi
  local dir="${PWD}"
  while [[ "${dir}" != "/" ]]; do
    if [[ -f "${dir}/ctrl.yaml" ]]; then
      CTRL_CONFIG_FILE="${dir}/ctrl.yaml"
      return
    fi
    dir="$(dirname "${dir}")"
  done
  fail "No ctrl.yaml found. Run 'ctrl init' or create one manually."
}

_require_yq() {
  require_cmd yq
}

# Resolve ${VAR} references in a string using current env
_resolve_env_refs() {
  echo "$1" | envsubst
}

load_config() {
  _find_config
  _require_yq
  msg_verbose "Loading config: ${CTRL_CONFIG_FILE}"

  # Load .local/ctrl.local.yaml overrides if present
  local local_cfg
  local_cfg="$(dirname "${CTRL_CONFIG_FILE}")/.local/ctrl.local.yaml"
  if [[ -f "${local_cfg}" ]]; then
    msg_verbose "Merging local overrides: ${local_cfg}"
    # yq merge: local overrides base (yq >=4 syntax)
    CTRL_YAML="$(yq '. *= load("'"${local_cfg}"'")' "${CTRL_CONFIG_FILE}")"
  else
    CTRL_YAML="$(cat "${CTRL_CONFIG_FILE}")"
  fi

  CTRL_META_PROJECT="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.project // ""')")"
  CTRL_META_REGISTRY="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.registry // ""')")"
  CTRL_META_SSH_HOST="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.ssh_host // ""')")"
  CTRL_META_SSH_USER="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.ssh_user // "root"')")"
  CTRL_META_SSH_PORT="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.ssh_port // "22"')")"
  CTRL_META_SSH_KEY="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.ssh_key // ""')")"
  CTRL_META_COMPOSE_PATH="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.compose_path // "/opt/scaffold/docker-compose.yml"')")"
  CTRL_META_REMOTE_DIR="$(dirname "${CTRL_META_COMPOSE_PATH}")"

  # Load env files listed in meta.env_files (optional)
  # Paths are relative to the ctrl.yaml directory
  local env_file ctrl_base
  ctrl_base="$(dirname "${CTRL_CONFIG_FILE}")"
  while IFS= read -r env_file; do
    [[ -z "${env_file}" || "${env_file}" == "null" ]] && continue
    env_file="$(_resolve_env_refs "${env_file}")"
    [[ "${env_file}" != /* ]] && env_file="${ctrl_base}/${env_file}"
    if [[ -f "${env_file}" ]]; then
      msg_verbose "Sourcing env file: ${env_file}"
      set -a; source "${env_file}"; set +a
    fi
  done < <(echo "${CTRL_YAML}" | yq '.meta.env_files[]? // ""')
}

# ── service accessors (read from CTRL_YAML) ───────────────────────────────────

ctrl_service_names() {
  echo "${CTRL_YAML}" | yq '.services[].name'
}

ctrl_service_field() {
  local svc="$1" field="$2"
  _resolve_env_refs "$(echo "${CTRL_YAML}" | yq ".services[] | select(.name == \"${svc}\") | ${field}")"
}

ctrl_service_exists() {
  local svc="$1"
  local found
  found="$(echo "${CTRL_YAML}" | yq ".services[] | select(.name == \"${svc}\") | .name" 2>/dev/null || true)"
  [[ -n "${found}" && "${found}" != "null" ]]
}

ctrl_resolve_services() {
  local -a out=()
  local token part normalized
  for token in "$@"; do
    IFS=',' read -r -a parts <<< "${token}"
    for part in "${parts[@]}"; do
      normalized="${part#"${part%%[![:space:]]*}"}"
      normalized="${normalized%"${normalized##*[![:space:]]}"}"
      normalized="$(tr '[:upper:]' '[:lower:]' <<< "${normalized}")"
      [[ -z "${normalized}" ]] && continue
      if [[ "${normalized}" == "all" ]]; then
        while IFS= read -r s; do out+=("${s}"); done < <(ctrl_service_names)
        echo "${out[@]}"; return
      fi
      ctrl_service_exists "${normalized}" || fail "Unknown service: ${normalized}"
      out+=("${normalized}")
    done
  done
  [[ "${#out[@]}" -gt 0 ]] || fail "No services resolved"
  echo "${out[@]}"
}

# ── SSH helpers ───────────────────────────────────────────────────────────────

_ssh_target() {
  [[ -n "${CTRL_META_SSH_HOST}" ]] || fail "meta.ssh_host is not set in ctrl.yaml"
  printf '%s@%s' "${CTRL_META_SSH_USER}" "${CTRL_META_SSH_HOST}"
}

_ssh_flags() {
  local flags=(-p "${CTRL_META_SSH_PORT}" -o StrictHostKeyChecking=accept-new)
  [[ -n "${CTRL_META_SSH_KEY}" ]] && flags+=(-i "${CTRL_META_SSH_KEY}")
  printf '%s\n' "${flags[@]}"
}

ctrl_ssh_run() {
  local command="$1"
  local target; target="$(_ssh_target)"
  local -a flags=()
  while IFS= read -r f; do flags+=("${f}"); done < <(_ssh_flags)
  if [[ -n "${SSH_PASSWORD:-}" ]] && has_cmd sshpass; then
    run_op "ssh ${target}" sshpass -p "${SSH_PASSWORD}" ssh "${flags[@]}" "${target}" "${command}"
  else
    run_op "ssh ${target}" ssh "${flags[@]}" "${target}" "${command}"
  fi
}

ctrl_scp_send() {
  local src="$1" dst="$2"
  local target; target="$(_ssh_target)"
  local -a flags=() # scp uses -P, but we build scp_flags below directly
  # rebuild properly
  local port="${CTRL_META_SSH_PORT}"
  local -a scp_flags=(-P "${port}" -o StrictHostKeyChecking=accept-new)
  [[ -n "${CTRL_META_SSH_KEY}" ]] && scp_flags+=(-i "${CTRL_META_SSH_KEY}")
  if [[ -n "${SSH_PASSWORD:-}" ]] && has_cmd sshpass; then
    run_op "scp ${src}" sshpass -p "${SSH_PASSWORD}" scp "${scp_flags[@]}" -r "${src}" "${target}:${dst}"
  else
    run_op "scp ${src}" scp "${scp_flags[@]}" -r "${src}" "${target}:${dst}"
  fi
}

# ── audit journal ─────────────────────────────────────────────────────────────

journal_entry() {
  local command="$1" services="$2" exit_code="$3" duration="$4"
  mkdir -p "${CTRL_JOURNAL_DIR}"
  printf '{"ts":"%s","version":"%s","project":"%s","command":"%s","services":"%s","host":"%s","operator":"%s","duration_s":%s,"exit_code":%s}\n' \
    "$(date -u +%Y-%m-%dT%H:%M:%SZ)" \
    "${CTRL_VERSION}" \
    "${CTRL_META_PROJECT}" \
    "${command}" \
    "${services}" \
    "${CTRL_META_SSH_HOST:-local}" \
    "${USER:-unknown}" \
    "${duration}" \
    "${exit_code}" \
    >> "${CTRL_JOURNAL}"
}

# Wrap a block and record it; usage: with_journal "cmd" "svc1 svc2" <function> [args]
with_journal() {
  local cmd="$1" svcs="$2"; shift 2
  local start; start="$(date +%s)"
  local exit_code=0
  "$@" || exit_code=$?
  local end; end="$(date +%s)"
  journal_entry "${cmd}" "${svcs}" "${exit_code}" "$((end - start))"
  return "${exit_code}"
}

# ════════════════════════════════════════════════════════════════════════════
# lib/services.sh
# ════════════════════════════════════════════════════════════════════════════
# services.sh — build (code + image), push, release

_svc_build_tool() { ctrl_service_field "$1" '.build.tool // "maven"'; }
_svc_build_dir()  { ctrl_service_field "$1" '.build.dir // ""'; }
_svc_build_args() { ctrl_service_field "$1" '.build.args // ""'; }
_svc_image()      { ctrl_service_field "$1" '.image // ""'; }
_svc_tag()        { ctrl_service_field "$1" '.tag // "latest"'; }
_svc_dockerfile() { ctrl_service_field "$1" '.build.dockerfile // "Dockerfile"'; }
_svc_context()    { ctrl_service_field "$1" '.build.context // ""'; }
_svc_platform()   { ctrl_service_field "$1" '.build.platform // "linux/amd64"'; }

_svc_image_ref() {
  local svc="$1"
  local image; image="$(_svc_image "${svc}")"
  local tag; tag="$(_svc_tag "${svc}")"
  [[ -n "${image}" ]] || fail "Service '${svc}' has no image defined in ctrl.yaml"
  printf '%s:%s' "${image}" "${tag}"
}

_svc_abs_dir() {
  local svc="$1"
  local dir; dir="$(_svc_build_dir "${svc}")"
  [[ -n "${dir}" ]] || fail "Service '${svc}' has no build.dir defined"
  # resolve relative to ctrl.yaml location
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"
  if [[ "${dir}" == /* ]]; then printf '%s' "${dir}"; else printf '%s/%s' "${base}" "${dir}"; fi
}

# ── sc-core / prerequisite builds ────────────────────────────────────────────
_SC_CORE_BUILT=0

_build_prerequisites() {
  local svc="$1"
  local prereqs; prereqs="$(echo "${CTRL_YAML}" | yq ".services[] | select(.name == \"${svc}\") | .build.prerequisites[]? // \"\"" 2>/dev/null || true)"
  [[ -z "${prereqs}" || "${prereqs}" == "null" ]] && return 0
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"
  local p
  while IFS= read -r p; do
    [[ -z "${p}" || "${p}" == "null" ]] && continue
    local abs_p="${base}/${p}"
    if [[ -f "${abs_p}/mvnw" ]]; then
      msg "Building prerequisite: ${p}"
      run_op "mvnw install ${p}" bash -c "cd '${abs_p}' && ./mvnw -Dmaven.test.skip=true clean install"
    elif [[ -f "${abs_p}/pom.xml" ]]; then
      msg "Building prerequisite: ${p}"
      run_op "mvn install ${p}" bash -c "cd '${abs_p}' && mvn -Dmaven.test.skip=true clean install"
    fi
  done <<< "${prereqs}"
}

# ── build code ────────────────────────────────────────────────────────────────
build_code_service() {
  local svc="$1"
  local tool; tool="$(_svc_build_tool "${svc}")"
  local dir; dir="$(_svc_abs_dir "${svc}")"
  local extra; extra="$(_svc_build_args "${svc}")"
  [[ -d "${dir}" ]] || fail "Build directory not found for '${svc}': ${dir}"

  _build_prerequisites "${svc}"

  case "${tool}" in
    maven)
      local wrapper="${dir}/mvnw"
      if [[ -f "${wrapper}" ]]; then
        run_op "build ${svc}" bash -c "cd '${dir}' && ./mvnw -Dmaven.test.skip=true clean package ${extra}"
      else
        run_op "build ${svc}" bash -c "cd '${dir}' && mvn -Dmaven.test.skip=true clean package ${extra}"
      fi
      ;;
    gradle)
      run_op "build ${svc}" bash -c "cd '${dir}' && ./gradlew build -x test ${extra}"
      ;;
    npm)
      run_op "build ${svc}" bash -c "cd '${dir}' && npm ci && npm run build ${extra}"
      ;;
    make)
      run_op "build ${svc}" bash -c "cd '${dir}' && make ${extra}"
      ;;
    shell)
      local script; script="$(ctrl_service_field "${svc}" '.build.script // ""')"
      [[ -n "${script}" ]] || fail "build.tool=shell requires build.script for service '${svc}'"
      run_op "build ${svc}" bash -c "cd '${dir}' && bash '${script}' ${extra}"
      ;;
    skip|none)
      msg_verbose "Skipping code build for ${svc} (tool=skip)"
      ;;
    *)
      fail "Unknown build.tool '${tool}' for service '${svc}'"
      ;;
  esac
  msg_ok "Built code: ${svc}"
}

# ── build image ───────────────────────────────────────────────────────────────
DOCKER_LOGGED_IN=0

_docker_login_once() {
  [[ "${DOCKER_LOGGED_IN}" -eq 0 ]] || return 0
  require_cmd docker
  local username="${DOCKERHUB_USERNAME:-}"
  local password="${DOCKERHUB_PASSWORD:-}"
  [[ -n "${username}" ]] || fail "DOCKERHUB_USERNAME is not set"
  [[ -n "${password}" ]] || fail "DOCKERHUB_PASSWORD is not set"
  msg "Logging into registry as ${username}"
  run_op "docker login" bash -c "printf '%s' '${password}' | docker login --username '${username}' --password-stdin"
  DOCKER_LOGGED_IN=1
}

build_image_service() {
  local svc="$1"
  local image_ref; image_ref="$(_svc_image_ref "${svc}")"
  local platform; platform="$(_svc_platform "${svc}")"

  local repo_dir; repo_dir="$(_svc_abs_dir "${svc}")"
  local dockerfile; dockerfile="$(_svc_dockerfile "${svc}")"
  local context; context="$(_svc_context "${svc}")"
  [[ -z "${context}" || "${context}" == "null" ]] && context="${repo_dir}"

  local df_path="${repo_dir}/${dockerfile}"
  [[ -f "${df_path}" ]] || fail "Dockerfile not found: ${df_path}"

  msg "Building image ${image_ref}"
  run_op "docker build ${svc}" docker buildx build \
    --platform "${platform}" \
    -f "${df_path}" \
    -t "${image_ref}" \
    --cache-from "type=registry,ref=${image_ref}-cache" \
    --cache-to   "type=registry,ref=${image_ref}-cache,mode=max" \
    "${context}"
  msg_ok "Built image: ${image_ref}"
}

push_image_service() {
  local svc="$1"
  local image_ref; image_ref="$(_svc_image_ref "${svc}")"
  _docker_login_once
  msg "Pushing ${image_ref}"
  run_op "docker push ${svc}" docker push "${image_ref}"
  msg_ok "Pushed: ${image_ref}"
}

release_service() {
  local svc="$1"
  build_code_service "${svc}"
  build_image_service "${svc}"
  push_image_service "${svc}"
}

