# lib/deploy.sh
# ════════════════════════════════════════════════════════════════════════════
# deploy.sh — deployment target resolution, sync, deploy

# ── deployment target resolution ──────────────────────────────────────────────
# Reads deployments: from ctrl.yaml and sets CTRL_DEPLOY_* vars for the target.
# After calling resolve_deployment, CTRL_META_* SSH vars are overridden with
# the target's values so that ctrl_ssh_run / ctrl_scp_send use them.

CTRL_DEPLOY_NAME=""
CTRL_DEPLOY_SYNC_PATHS=()

resolve_deployment() {
  local target_name="${1:-}"

  # Find default name if not specified
  if [[ -z "${target_name}" ]]; then
    target_name="$(echo "${CTRL_YAML}" | yq '.deployments.default // ""')"
    [[ -n "${target_name}" && "${target_name}" != "null" ]] || \
      fail "No deployment target specified and no deployments.default set in ctrl.yaml"
  fi

  # Check the target exists
  local found; found="$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .name" 2>/dev/null || true)"
  [[ -n "${found}" && "${found}" != "null" ]] || \
    fail "Deployment target '${target_name}' not found in ctrl.yaml deployments.targets"

  CTRL_DEPLOY_NAME="${target_name}"

  # Override SSH meta with target-specific values (falls back to meta defaults)
  local t_ssh_host; t_ssh_host="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .ssh_host // \"\"")")"
  local t_ssh_user; t_ssh_user="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .ssh_user // \"\"")")"
  local t_ssh_port; t_ssh_port="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .ssh_port // \"\"")")"
  local t_ssh_key;  t_ssh_key="$(_resolve_env_refs  "$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .ssh_key // \"\"")")"
  local t_compose;  t_compose="$(_resolve_env_refs  "$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .compose_path // \"\"")")"

  [[ -n "${t_ssh_host}"  && "${t_ssh_host}"  != "null" ]] && CTRL_META_SSH_HOST="${t_ssh_host}"
  [[ -n "${t_ssh_user}"  && "${t_ssh_user}"  != "null" ]] && CTRL_META_SSH_USER="${t_ssh_user}"
  [[ -n "${t_ssh_port}"  && "${t_ssh_port}"  != "null" ]] && CTRL_META_SSH_PORT="${t_ssh_port}"
  [[ -n "${t_ssh_key}"   && "${t_ssh_key}"   != "null" ]] && CTRL_META_SSH_KEY="${t_ssh_key}"
  [[ -n "${t_compose}"   && "${t_compose}"   != "null" ]] && { CTRL_META_COMPOSE_PATH="${t_compose}"; CTRL_META_REMOTE_DIR="$(dirname "${t_compose}")"; }

  # Load sync paths for this target
  CTRL_DEPLOY_SYNC_PATHS=()
  while IFS= read -r p; do
    [[ -z "${p}" || "${p}" == "null" ]] && continue
    CTRL_DEPLOY_SYNC_PATHS+=("${p}")
  done < <(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${target_name}\") | .sync.paths[]? // \"\"")

  msg_verbose "Deployment target: ${CTRL_DEPLOY_NAME} → ${CTRL_META_SSH_USER}@${CTRL_META_SSH_HOST}:${CTRL_META_REMOTE_DIR}"
}

# Returns 0 if $1 is a known deployment target name, 1 otherwise
is_deployment_target() {
  local candidate="${1:-}"
  [[ -z "${candidate}" ]] && return 1
  local found; found="$(echo "${CTRL_YAML}" | yq ".deployments.targets[] | select(.name == \"${candidate}\") | .name" 2>/dev/null || true)"
  [[ -n "${found}" && "${found}" != "null" ]]
}

# ── service helpers ───────────────────────────────────────────────────────────

_svc_compose_service() {
  local svc="$1"
  local cs; cs="$(ctrl_service_field "${svc}" '.deploy.compose_service // ""')"
  [[ -n "${cs}" && "${cs}" != "null" ]] && printf '%s' "${cs}" || printf '%s' "${svc}"
}

_svc_compose_deps() {
  local svc="$1"
  echo "${CTRL_YAML}" | yq ".services[] | select(.name == \"${svc}\") | .deploy.depends_on[]? // \"\"" 2>/dev/null || true
}

_remote_export_block() {
  local svc
  local -a exports=()
  for svc in "$@"; do
    local img; img="$(ctrl_service_field "${svc}" '.image // ""')"
    local tag; tag="$(ctrl_service_field "${svc}" '.tag // "latest"')"
    [[ -z "${img}" || "${img}" == "null" ]] && continue
    local upper_name; upper_name="$(tr '[:lower:]-' '[:upper:]_' <<< "${svc}")"
    exports+=("export ${upper_name}_IMAGE=$(printf '%q' "${img}") ${upper_name}_TAG=$(printf '%q' "${tag}")")
  done
  [[ "${#exports[@]}" -gt 0 ]] && printf '%s; ' "${exports[@]}" || true
}

_remote_compose_services() {
  local svc
  local -a out=()
  for svc in "$@"; do out+=("$(_svc_compose_service "${svc}")"); done
  printf '%s ' "${out[@]}"
}

_remote_dep_services() {
  local svc dep
  local -a out=()
  for svc in "$@"; do
    while IFS= read -r dep; do
      [[ -z "${dep}" || "${dep}" == "null" ]] && continue
      out+=("${dep}")
    done < <(_svc_compose_deps "${svc}")
  done
  [[ "${#out[@]}" -gt 0 ]] && printf '%s ' "${out[@]}" || true
}

# ── deploy ────────────────────────────────────────────────────────────────────

deploy_services() {
  local -a svcs=("$@")
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  local exports; exports="$(_remote_export_block "${svcs[@]}")"; exports="${exports%'; '}"
  local compose_svcs; compose_svcs="$(_remote_compose_services "${svcs[@]}" | sed 's/ $//')"
  local dep_svcs; dep_svcs="$(_remote_dep_services "${svcs[@]}" | sed 's/ $//')"

  [[ -n "${compose_svcs// }" ]] || fail "No compose services resolved for: ${svcs[*]}"

  local cmd="cd $(printf '%q' "${remote_dir}")"
  [[ -n "${exports}" ]] && cmd+=" && ${exports}"
  [[ -n "${dep_svcs// }" ]] && cmd+=" && docker compose up -d ${dep_svcs}"
  cmd+=" && docker compose pull ${compose_svcs} && docker compose up -d --no-deps --force-recreate ${compose_svcs}"

  msg "[$CTRL_DEPLOY_NAME] Deploying: ${compose_svcs}"
  ctrl_ssh_run "${cmd}"
  msg_ok "[$CTRL_DEPLOY_NAME] Deploy finished"
}

# ── sync ──────────────────────────────────────────────────────────────────────

sync_files() {
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"

  if [[ "${#CTRL_DEPLOY_SYNC_PATHS[@]}" -eq 0 ]]; then
    msg_warn "[$CTRL_DEPLOY_NAME] No sync.paths defined for this target; nothing to sync"
    return 0
  fi

  msg "[$CTRL_DEPLOY_NAME] Syncing → ${CTRL_META_SSH_HOST}:${remote_dir}"
  ctrl_ssh_run "mkdir -p $(printf '%q' "${remote_dir}")"
  local p abs_p
  for p in "${CTRL_DEPLOY_SYNC_PATHS[@]}"; do
    abs_p="${base}/${p}"
    [[ -e "${abs_p}" ]] || { msg_warn "Sync path not found, skipping: ${abs_p}"; continue; }
    ctrl_scp_send "${abs_p}" "${remote_dir}/"
  done
  msg_ok "[$CTRL_DEPLOY_NAME] Sync complete"
}

# ════════════════════════════════════════════════════════════════════════════
# lib/remote.sh
# ════════════════════════════════════════════════════════════════════════════
# remote.sh — ssh, remote-status, remote-logs, inspect

open_ssh() {
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  local target; target="${CTRL_META_SSH_USER}@${CTRL_META_SSH_HOST}"
  local port="${CTRL_META_SSH_PORT}"
  local cmd="cd $(printf '%q' "${remote_dir}") && exec \${SHELL:-bash} -l"

  local -a flags=(-t -p "${port}" -o StrictHostKeyChecking=accept-new)
  [[ -n "${CTRL_META_SSH_KEY}" ]] && flags+=(-i "${CTRL_META_SSH_KEY}")

  if [[ -n "${SSH_PASSWORD:-}" ]] && has_cmd sshpass; then
    sshpass -p "${SSH_PASSWORD}" ssh "${flags[@]}" "${target}" "${cmd}"
  else
    ssh "${flags[@]}" "${target}" "${cmd}"
  fi
}

remote_status() {
  local svc="${1:-}"
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  if [[ -n "${svc}" ]]; then
    local cs; cs="$(_svc_compose_service "${svc}")"
    ctrl_ssh_run "cd $(printf '%q' "${remote_dir}") && docker compose ps ${cs}"
  else
    ctrl_ssh_run "cd $(printf '%q' "${remote_dir}") && docker compose ps"
  fi
}

remote_logs() {
  local svc="$1"
  local lines="${2:-200}"
  local follow="${CTRL_FOLLOW:-0}"
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  ctrl_service_exists "${svc}" || fail "Unknown service: ${svc}"
  local cs; cs="$(_svc_compose_service "${svc}")"
  local tail_flag="--tail ${lines}"
  local follow_flag=""
  [[ "${follow}" == "1" ]] && follow_flag="--follow"
  ctrl_ssh_run "cd $(printf '%q' "${remote_dir}") && docker compose logs ${tail_flag} ${follow_flag} ${cs}"
}

remote_inspect() {
  local svc="$1"
  ctrl_service_exists "${svc}" || fail "Unknown service: ${svc}"
  local cs; cs="$(_svc_compose_service "${svc}")"
  local remote_dir="${CTRL_META_REMOTE_DIR}"
  ctrl_ssh_run "cd $(printf '%q' "${remote_dir}") && docker compose exec ${cs} env | sort"
}

# ════════════════════════════════════════════════════════════════════════════
# lib/health.sh
# ════════════════════════════════════════════════════════════════════════════
# health.sh — health-check, wait-ready, smoke-test

_svc_health_url() {
  local svc="$1"
  local url; url="$(ctrl_service_field "${svc}" '.health.url // ""')"
  [[ -n "${url}" && "${url}" != "null" ]] && printf '%s' "${url}" && return
  # derive from meta.registry host or local defaults
  local port; port="$(ctrl_service_field "${svc}" '.health.port // ""')"
  [[ -n "${port}" && "${port}" != "null" ]] && printf 'http://localhost:%s/actuator/health' "${port}" && return
  printf ''
}

health_check_service() {
  local svc="$1"
  ctrl_service_exists "${svc}" || fail "Unknown service: ${svc}"
  local url; url="$(_svc_health_url "${svc}")"
  [[ -n "${url}" ]] || { msg_warn "No health.url or health.port for ${svc} — skipping"; return 0; }
  require_cmd curl

  # If a deployment target is active, run the curl on the remote VM
  if [[ -n "${CTRL_META_SSH_HOST:-}" ]]; then
    msg "Health check: ${svc} → ${url} (via ${CTRL_META_SSH_HOST})"
    local http_code
    http_code="$(ctrl_ssh_run "curl -s -o /dev/null -w '%{http_code}' --max-time 5 '${url}'" || echo "000")"
    http_code="${http_code//[[:space:]]/}"
  else
    msg "Health check: ${svc} → ${url}"
    local http_code
    http_code="$(run_op "curl ${url}" curl -s -o /dev/null -w '%{http_code}' --max-time 5 "${url}" || echo "000")"
  fi

  if [[ "${http_code}" == "200" ]]; then
    msg_ok "${svc} is healthy (HTTP ${http_code})"
  else
    msg_error "${svc} returned HTTP ${http_code} at ${url}"
    return 1
  fi
}

wait_ready_service() {
  local svc="$1"
  local timeout="${2:-60}"
  ctrl_service_exists "${svc}" || fail "Unknown service: ${svc}"
  local url; url="$(_svc_health_url "${svc}")"
  [[ -n "${url}" ]] || { msg_warn "No health.url or health.port for ${svc} — skipping"; return 0; }
  require_cmd curl
  msg "Waiting for ${svc} to be ready (timeout: ${timeout}s)"
  local elapsed=0
  while [[ "${elapsed}" -lt "${timeout}" ]]; do
    local http_code
    http_code="$(curl -s -o /dev/null -w '%{http_code}' --max-time 3 "${url}" 2>/dev/null || echo "000")"
    if [[ "${http_code}" == "200" ]]; then
      msg_ok "${svc} is ready"
      return 0
    fi
    sleep 2
    elapsed=$((elapsed + 2))
  done
  fail "${svc} did not become ready within ${timeout}s"
}

smoke_test_services() {
  local -a svcs=("$@")
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"
  local svc script_name script_path
  local found=0

  for svc in "${svcs[@]}"; do
    while IFS= read -r script_name; do
      [[ -z "${script_name}" || "${script_name}" == "null" ]] && continue
      found=1
      # find the script in the scripts list
      script_path="$(echo "${CTRL_YAML}" | yq ".scripts[] | select(.name == \"${script_name}\") | .path // \"\"" || true)"
      [[ -n "${script_path}" && "${script_path}" != "null" ]] || fail "Smoke test script '${script_name}' not found in scripts:"
      local abs="${base}/${script_path}"
      [[ -f "${abs}" ]] || fail "Script file not found: ${abs}"
      msg "Smoke test [${svc}]: ${script_name}"
      run_op "smoke ${script_name}" bash "${abs}"
    done < <(echo "${CTRL_YAML}" | yq ".services[] | select(.name == \"${svc}\") | .smoke_tests[]? // \"\"")
  done

  [[ "${found}" -eq 1 ]] || msg_warn "No smoke tests defined for: ${svcs[*]}"
}

# ════════════════════════════════════════════════════════════════════════════
# lib/audit.sh
# ════════════════════════════════════════════════════════════════════════════
# audit.sh — history display, journal helpers (journal_entry is in core.sh)

show_history() {
  local lines="${1:-20}"
  [[ -f "${CTRL_JOURNAL}" ]] || { msg_warn "No journal found at ${CTRL_JOURNAL}"; return 0; }
  require_cmd jq
  tail -n "${lines}" "${CTRL_JOURNAL}" | jq -r \
    '"\(.ts)  \(.command | @sh)  svcs=\(.services)  exit=\(.exit_code)  \(.duration_s)s"'
}

# ════════════════════════════════════════════════════════════════════════════
# lib/ext.sh
# ════════════════════════════════════════════════════════════════════════════
# ext.sh — named script runner and plugin (extension) loader

run_script() {
  local name="$1"; shift
  local extra_args=("$@")
  while [[ "${#extra_args[@]}" -gt 0 && "${extra_args[0]}" == "--" ]]; do
    extra_args=("${extra_args[@]:1}")
  done
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"

  local path
  path="$(echo "${CTRL_YAML}" | yq ".scripts[] | select(.name == \"${name}\") | .path // \"\"" 2>/dev/null || true)"
  [[ -n "${path}" && "${path}" != "null" ]] || fail "Script '${name}' not found in ctrl.yaml scripts:"

  local abs="${base}/${path}"
  [[ -f "${abs}" ]] || fail "Script file not found: ${abs}"

  export CTRL_PROJECT="${CTRL_META_PROJECT}"
  export CTRL_SSH_HOST="${CTRL_META_SSH_HOST}"
  export CTRL_REGISTRY="${CTRL_META_REGISTRY}"
  export CTRL_REMOTE_DIR="${CTRL_META_REMOTE_DIR}"
  export CTRL_CONFIG_FILE
  export F33D_URL; F33D_URL="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.f33d.url // ""')")"
  export F33D_TOKEN; F33D_TOKEN="$(_resolve_env_refs "$(echo "${CTRL_YAML}" | yq '.meta.f33d.token // ""')")"

  local hook
  while IFS= read -r hook; do
    [[ -z "${hook}" || "${hook}" == "null" ]] && continue
    run_script "${hook}"
  done < <(echo "${CTRL_YAML}" | yq ".scripts[] | select(.name == \"${name}\") | .hooks.pre[]? // \"\"")

  msg "Running script: ${name}"
  local exit_code=0
  run_op "script ${name}" bash "${abs}" "${extra_args[@]+"${extra_args[@]}"}" || exit_code=$?

  export CTRL_EXIT_CODE="${exit_code}"
  if [[ "${exit_code}" -ne 0 ]]; then export F33D_LEVEL="error"; else export F33D_LEVEL="success"; fi
  if [[ "${exit_code}" -ne 0 ]]; then export F33D_MESSAGE="ctrl ${name}: failed"; else export F33D_MESSAGE="ctrl ${name}: done"; fi
  while IFS= read -r hook; do
    [[ -z "${hook}" || "${hook}" == "null" ]] && continue
    run_script "${hook}" || true
  done < <(echo "${CTRL_YAML}" | yq ".scripts[] | select(.name == \"${name}\") | .hooks.post[]? // \"\"")

  [[ "${exit_code}" -eq 0 ]] || return "${exit_code}"
  msg_ok "Script finished: ${name}"
}

list_scripts() {
  echo "${CTRL_YAML}" | yq '.scripts[] | "\(.name)\t\(.description // "")"' | \
    while IFS=$'\t' read -r name desc; do
      printf '  %-24s %s\n' "${name}" "${desc}"
    done
}

load_extensions() {
  local base; base="$(dirname "${CTRL_CONFIG_FILE}")"
  local p abs
  while IFS= read -r p; do
    [[ -z "${p}" || "${p}" == "null" ]] && continue
    abs="${base}/${p}"
    if [[ -f "${abs}" ]]; then
      msg_verbose "Loading extension: ${abs}"
      # shellcheck disable=SC1090
      source "${abs}"
    else
      msg_warn "Extension not found, skipping: ${abs}"
    fi
  done < <(echo "${CTRL_YAML}" | yq '.extensions[]? // ""')
}

# ════════════════════════════════════════════════════════════════════════════
# ctrl.sh — entry point
# ════════════════════════════════════════════════════════════════════════════




# ── helpers ───────────────────────────────────────────────────────────────────
run_for_each() {
  local action="$1"; shift
  for svc in "$@"; do "${action}" "${svc}"; done
}

run_for_each_continue() {
  local action="$1"; shift
  local failed=0
  for svc in "$@"; do "${action}" "${svc}" || failed=1; done
  return "${failed}"
}

# Resolve optional deployment target from first arg.
# If $1 is a known deployment name, sets it and shifts CTRL_ARGS.
# Otherwise uses the default target. Remaining CTRL_ARGS are service selectors.
_resolve_target_and_services() {
  local -a args=("$@")
  if [[ "${#args[@]}" -gt 0 ]] && is_deployment_target "${args[0]}"; then
    resolve_deployment "${args[0]}"
    args=("${args[@]:1}")
  else
    resolve_deployment ""
  fi
  # Return remaining args as services (caller reads CTRL_SVC_ARGS)
  CTRL_SVC_ARGS=("${args[@]+"${args[@]}"}")
}

# ── global flag parsing ───────────────────────────────────────────────────────
CTRL_FOLLOW=0
_parse_global_flags() {
  local -a remaining=()
  while [[ "$#" -gt 0 ]]; do
    case "$1" in
      --dry-run)    CTRL_DRY_RUN=1 ;;
      --verbose|-v) CTRL_VERBOSE=1 ;;
      --config)     shift; CTRL_CONFIG_FILE="$1" ;;
      --follow)     CTRL_FOLLOW=1 ;;
      *)            remaining+=("$1") ;;
    esac
    shift
  done
  CTRL_ARGS=("${remaining[@]+"${remaining[@]}"}")
}

_parse_global_flags "$@"
set -- "${CTRL_ARGS[@]+"${CTRL_ARGS[@]}"}"

# ── version / help (no config needed) ────────────────────────────────────────
case "${1:-}" in
  version|--version|-V)
    echo "ctrl v${CTRL_VERSION}"
    exit 0
    ;;
  help|--help|-h|"")
    cat <<EOF
ctrl v${CTRL_VERSION} — YAML-driven platform operations CLI

Usage: ctrl [--dry-run] [--verbose] [--config <path>] <command> [args]

Service commands:
  list  / ls                        List services defined in ctrl.yaml
  build / b    <svc|all>            Build service code locally
  image / i    <svc|all>            Build Docker image (no push)
  push  / pu   <svc|all>            Push image to registry
  rel          <svc|all>            build + image + push
  dep          [target] [svc|all]   Pull and start on deployment target (default: deployments.default)
  rdep         [target] [svc|all]   rel + dep

Deployment commands:
  sync         [target]             Sync files to deployment target
  dep          [target] [svc|all]   Pull + start services on target
  rdep         [target] [svc|all]   rel + dep on target

Remote commands:
  ssh / sr     [target] [cmd]        Interactive SSH or run a remote command
  rs           [svc]                Remote status (docker compose ps)
  rl           <svc> [lines]        Remote logs (--follow to tail)
  insp         <svc>                Show env of running container

Health commands:
  hc           [svc|all]            Health check
  wr           <svc> [timeout]      Wait until healthy
  st           [svc|all]            Smoke test

Script commands:
  run          <name> [args]        Run a named script
  scripts      / sc                 List scripts

Audit:
  hist         [n]                  Last n journal entries (default 20)
  plan                              Dry-run mode (alias for --dry-run)
  version                           Print ctrl version

Global flags:
  --dry-run    -n                   Print commands, no execution
  --verbose    -v                   Extra debug output
  --config     <path>               Override ctrl.yaml location
  --follow                          Tail logs (with rl)

Deployment targets are defined under deployments: in ctrl.yaml.
When [target] is omitted, deployments.default is used.

EOF
    exit 0
    ;;
esac

# ── commands that need config ─────────────────────────────────────────────────
load_config
load_extensions

CMD="${1:-}"; shift || true
CTRL_SVC_ARGS=()

case "${CMD}" in

  # ── GitLab project info ───────────────────────────────────────────────
  gitlab-project-info)
    [[ "$#" -ge 1 ]] || fail "Usage: ctrl gitlab-project-info <project-id-or-path>"
    ctrl_gitlab_project_info "$1"
    ;;

  # ── GitLab runner deploy ──────────────────────────────────────────────
  gitlab-runner-deploy)
    ctrl_gitlab_runner_deploy
    ;;

  # ── list ──────────────────────────────────────────────────────────────────
  list|ls)
    printf '%s%-20s %-40s %s%s\n' "${BOLD}" "SERVICE" "DESCRIPTION" "IMAGE:TAG" "${RESET}"
    while IFS= read -r svc; do
      svc_img="$(ctrl_service_field "${svc}" '.image // "-"'):$(ctrl_service_field "${svc}" '.tag // "latest"')"
      svc_desc="$(ctrl_service_field "${svc}" '.description // ""')"
      printf '  %-20s %-40s %s\n' "${svc}" "${svc_desc}" "${svc_img}"
    done < <(ctrl_service_names)
    ;;

  # ── build ─────────────────────────────────────────────────────────────────
  build|b)
    [[ "$#" -gt 0 ]] || fail "Usage: ctrl b <svc|all>"
    read -r -a svcs <<< "$(ctrl_resolve_services "$@")"
    with_journal "build" "${svcs[*]}" run_for_each build_code_service "${svcs[@]}"
    ;;

  # ── image ─────────────────────────────────────────────────────────────────
  image|i)
    [[ "$#" -gt 0 ]] || fail "Usage: ctrl i <svc|all>"
    read -r -a svcs <<< "$(ctrl_resolve_services "$@")"
    with_journal "image" "${svcs[*]}" run_for_each build_image_service "${svcs[@]}"
    ;;

  # ── push ──────────────────────────────────────────────────────────────────
  push|pu)
    [[ "$#" -gt 0 ]] || fail "Usage: ctrl pu <svc|all>"
    read -r -a svcs <<< "$(ctrl_resolve_services "$@")"
    with_journal "push" "${svcs[*]}" run_for_each push_image_service "${svcs[@]}"
    ;;

  # ── release ───────────────────────────────────────────────────────────────
  release|rel)
    [[ "$#" -gt 0 ]] || fail "Usage: ctrl rel <svc|all>"
    read -r -a svcs <<< "$(ctrl_resolve_services "$@")"
    with_journal "release" "${svcs[*]}" run_for_each release_service "${svcs[@]}"
    ;;

  # ── sync ──────────────────────────────────────────────────────────────────
  sync)
    _resolve_target_and_services "$@"
    with_journal "sync" "${CTRL_DEPLOY_NAME}" sync_files
    ;;

  # ── deploy ────────────────────────────────────────────────────────────────
  deploy|dep)
    _resolve_target_and_services "$@"
    if [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 ]]; then
      read -r -a svcs <<< "$(ctrl_resolve_services "${CTRL_SVC_ARGS[@]}")"
    else
      read -r -a svcs <<< "$(ctrl_resolve_services all)"
    fi
    with_journal "deploy" "${CTRL_DEPLOY_NAME}:${svcs[*]}" deploy_services "${svcs[@]}"
    ;;

  # ── redeploy ──────────────────────────────────────────────────────────────
  redeploy|rdep)
    _resolve_target_and_services "$@"
    if [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 ]]; then
      read -r -a svcs <<< "$(ctrl_resolve_services "${CTRL_SVC_ARGS[@]}")"
    else
      read -r -a svcs <<< "$(ctrl_resolve_services all)"
    fi
    run_for_each release_service "${svcs[@]}"
    with_journal "redeploy" "${CTRL_DEPLOY_NAME}:${svcs[*]}" deploy_services "${svcs[@]}"
    ;;

  # ── sync + deploy ─────────────────────────────────────────────────────────
  sync-deploy|sdep)
    _resolve_target_and_services "$@"
    if [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 ]]; then
      read -r -a svcs <<< "$(ctrl_resolve_services "${CTRL_SVC_ARGS[@]}")"
    else
      read -r -a svcs <<< "$(ctrl_resolve_services all)"
    fi
    sync_files
    with_journal "sync-deploy" "${CTRL_DEPLOY_NAME}:${svcs[*]}" deploy_services "${svcs[@]}"
    ;;

  # ── ssh / sr ──────────────────────────────────────────────────────────────
  ssh|sr)
    _resolve_target_and_services "$@"
    # strip leading '--' option-separator that users sometimes include
    while [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 && "${CTRL_SVC_ARGS[0]}" == "--" ]]; do
      CTRL_SVC_ARGS=("${CTRL_SVC_ARGS[@]:1}")
    done
    if [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 ]]; then
      ctrl_ssh_run "${CTRL_SVC_ARGS[*]}"
    else
      open_ssh
    fi
    ;;

  # ── remote-status ─────────────────────────────────────────────────────────
  remote-status|rs)
    _resolve_target_and_services "$@"
    remote_status "${CTRL_SVC_ARGS[0]:-}"
    ;;

  # ── remote-logs ───────────────────────────────────────────────────────────
  remote-logs|rl)
    _resolve_target_and_services "$@"
    [[ "${#CTRL_SVC_ARGS[@]}" -ge 1 ]] || fail "Usage: ctrl rl [target] <svc> [lines]"
    remote_logs "${CTRL_SVC_ARGS[0]}" "${CTRL_SVC_ARGS[1]:-200}"
    ;;

  # ── inspect ───────────────────────────────────────────────────────────────
  inspect|insp)
    _resolve_target_and_services "$@"
    [[ "${#CTRL_SVC_ARGS[@]}" -ge 1 ]] || fail "Usage: ctrl insp [target] <svc>"
    remote_inspect "${CTRL_SVC_ARGS[0]}"
    ;;

  # ── health-check ──────────────────────────────────────────────────────────
  health-check|hc)
    _resolve_target_and_services "$@"
    svcs=()
    if [[ "${#CTRL_SVC_ARGS[@]}" -gt 0 ]]; then
      read -r -a svcs <<< "$(ctrl_resolve_services "${CTRL_SVC_ARGS[@]}")"
    else
      read -r -a svcs <<< "$(ctrl_resolve_services all)"
    fi
    run_for_each_continue health_check_service "${svcs[@]}"
    ;;

  # ── wait-ready ────────────────────────────────────────────────────────────
  wait-ready|wr)
    [[ "$#" -ge 1 ]] || fail "Usage: ctrl wr <svc> [timeout]"
    wait_ready_service "$1" "${2:-60}"
    ;;

  # ── smoke-test ────────────────────────────────────────────────────────────
  smoke-test|st)
    if [[ "$#" -gt 0 ]]; then
      read -r -a svcs <<< "$(ctrl_resolve_services "$@")"
    else
      read -r -a svcs <<< "$(ctrl_resolve_services all)"
    fi
    smoke_test_services "${svcs[@]}"
    ;;

  # ── run script ────────────────────────────────────────────────────────────
  run)
    [[ "$#" -ge 1 ]] || fail "Usage: ctrl run <name> [args]"
    _script_name="$1"; shift
    run_script "${_script_name}" "$@"
    ;;

  # ── list scripts ──────────────────────────────────────────────────────────
  scripts|sc)
    printf '%s%-24s %s%s\n' "${BOLD}" "SCRIPT" "DESCRIPTION" "${RESET}"
    list_scripts
    ;;

  # ── history ───────────────────────────────────────────────────────────────
  history|hist)
    show_history "${1:-20}"
    ;;

  # ── plan / dry-run ────────────────────────────────────────────────────────
  plan)
    CTRL_DRY_RUN=1
    msg "Dry-run mode — no changes will be made. Use --dry-run on any command for the same effect."
    ;;

  version)
    echo "ctrl v${CTRL_VERSION}"
    ;;

  # ── extension commands ────────────────────────────────────────────────────
  *)
    _ext_fn="ctrl_cmd_${CMD//-/_}"
    if declare -f "${_ext_fn}" >/dev/null 2>&1; then
      "${_ext_fn}" "$@"
    else
      fail "Unknown command: ${CMD}. Run 'ctrl help' for usage."
    fi
    ;;
esac
